create table dirkspzm32.isi_contact (
    sid             varchar2(2 char) default '01' not null enable,
    firma_nr        number(6, 0) default 1 not null enable,
    contact_id      number(*, 0) not null enable,
    aktiv           varchar2(1 char) default 'T' not null enable,
    anrede          varchar2(20 char),
    nachname        varchar2(255 char),
    vorname         varchar2(255 char),
    telefon_nr      varchar2(50 char),
    pers_nr         number(*, 0),
    email           varchar2(80 char),
    fax             varchar2(40 char),
    adress_id       number(*, 0),
    create_date     date,
    create_login_id number(*, 0),
    change_date     date,
    change_login_id number(*, 0),
    login_id        number(*, 0)
);

alter table dirkspzm32.isi_contact
    add constraint pk_isi_contact primary key ( contact_id )
        using index enable;

alter table dirkspzm32.isi_contact add constraint uk_ix_isi_contact_login unique ( login_id )
    using index enable;


